    let remaining = typeComponents.length;
    while (remaining >= COMPONENT_BLOCK_SIZE) {
      // Block is treated as a single unit for modifiers
      modifiedPremium += COMPONENT_BLOCK_PREMIUM;
      remaining -= COMPONENT_BLOCK_SIZE;
    }

    for (let i = 0; i < remaining; i++) {
